   1→import { createContext, useContext, useReducer } from 'react';
   2→import { createProject } from '@/domain/models';
   3→import { clearProjectPhaseReferences } from '@/domain/phaseAssignments';
   4→import { createDuplicatedFloor, getDefaultFloorName, getFloorElevation, getFloorLevelIndex, shiftFloorAbsoluteElements, shiftFloorElevationData, sortFloors } from '@/domain/floorModels';
   5→import { sortPhases } from '@/domain/phaseModels';
   6→import { getAttachedTrussSystem, getRoofAttachmentElevation, syncProjectRoofSystem } from '@/domain/roofModels';
   7→import { syncProjectTrussSystems } from '@/domain/trussModels';
   8→import { detachColumnAttachments, syncWallAttachmentPoints } from '@/geometry/wallColumnGeometry';
   9→import { syncStairLandingAttachment } from '@/geometry/landingGeometry';
  10→import { clampWallOpeningOffset, wallLength } from '@/geometry/wallGeometry';
  11→
  12→const ProjectContext = createContext(null);
  13→const HISTORY_LIMIT = 100;
  14→
  15→function snapshotProject(project) {
  16→  return JSON.stringify(project);
  17→}
  18→
  19→function syncProjectStructures(project) {
  20→  return syncProjectRoofSystem(syncProjectTrussSystems(project));
  21→}
  22→
  23→function applyProjectUpdate(state, nextProject, recordHistory = true) {
  24→  const syncedProject = syncProjectStructures(nextProject);
  25→  const nextSnapshot = snapshotProject(syncedProject);
  26→  const history = recordHistory
  27→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
  28→    : state.history;
  29→
  30→  return {
  31→    ...state,
  32→    history,
  33→    future: recordHistory ? [] : state.future,
  34→    project: syncedProject,
  35→    isDirty: nextSnapshot !== state.savedSnapshot,
  36→  };
  37→}
  38→
  39→function updateFloor(state, floorId, updater, recordHistory = true, options = {}) {
  40→  const nextFloors = state.project.floors.map((floor) => (
  41→    floor.id === floorId ? updater(floor) : floor
  42→  ));
  43→
  44→  return applyProjectUpdate(state, {
  45→    ...state.project,
  46→    updatedAt: new Date().toISOString(),
  47→    floors: options.sort ? sortFloors(nextFloors) : nextFloors,
  48→  }, recordHistory);
  49→}
  50→
  51→function replaceFloors(state, floors, recordHistory = true) {
  52→  return applyProjectUpdate(state, {
  53→    ...state.project,
  54→    updatedAt: new Date().toISOString(),
  55→    floors: sortFloors(floors),
  56→  }, recordHistory);
  57→}
  58→
  59→function replaceDeletedFloorReferences(project, deletedFloorId, fallbackFloorId) {
  60→  return {
  61→    ...project,
  62→    floors: project.floors.map((floor) => ({
  63→      ...floor,
  64→      stairs: (floor.stairs || []).map((stair) => ({
  65→        ...stair,
  66→        floorRelation: {
  67→          fromFloorId: stair.floorRelation?.fromFloorId === deletedFloorId
  68→            ? fallbackFloorId
  69→            : (stair.floorRelation?.fromFloorId ?? floor.id),
  70→          toFloorId: stair.floorRelation?.toFloorId === deletedFloorId
  71→            ? fallbackFloorId
  72→            : (stair.floorRelation?.toFloorId ?? floor.id),
  73→        },
  74→      })),
  75→    })),
  76→    sheets: (project.sheets || []).map((sheet) => ({
  77→      ...sheet,
  78→      viewports: (sheet.viewports || []).map((viewport) => ({
  79→        ...viewport,
  80→        sourceFloorId: viewport.sourceFloorId === deletedFloorId
  81→          ? fallbackFloorId
  82→          : viewport.sourceFloorId,
  83→        sourceRefId: viewport.sourceFloorId === deletedFloorId
  84→          ? null
  85→          : viewport.sourceRefId,
  86→      })),
  87→    })),
  88→  };
  89→}
  90→
  91→function clearStairRoofAccessReferences(project, roofOpeningId = null) {
  92→  return {
  93→    ...project,
  94→    floors: (project.floors || []).map((floor) => ({
  95→      ...floor,
  96→      stairs: (floor.stairs || []).map((stair) => {
  97→        const currentRoofOpeningId = stair.roofAccess?.roofOpeningId || null;
  98→        if (!currentRoofOpeningId) return stair;
  99→        if (roofOpeningId && currentRoofOpeningId !== roofOpeningId) return stair;
 100→        return {
 101→          ...stair,
 102→          roofAccess: null,
 103→        };
 104→      }),
 105→    })),
 106→  };
 107→}
 108→
 109→function updateRoofSystem(state, updater, recordHistory = true) {
 110→  const nextRoofSystem = updater(state.project.roofSystem);
 111→  return applyProjectUpdate(state, {
 112→    ...state.project,
 113→    updatedAt: new Date().toISOString(),
 114→    roofSystem: nextRoofSystem,
 115→  }, recordHistory);
 116→}
 117→
 118→function updateTrussSystems(state, updater, recordHistory = true) {
 119→  const nextTrussSystems = updater(state.project.trussSystems || []);
 120→  return applyProjectUpdate(state, {
 121→    ...state.project,
 122→    updatedAt: new Date().toISOString(),
 123→    trussSystems: nextTrussSystems,
 124→  }, recordHistory);
 125→}
 126→
 127→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 128→  const nextWall = { ...existingWall, ...wallUpdate };
 129→
 130→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 131→    nextWall.startAttachment = null;
 132→  }
 133→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 134→    nextWall.endAttachment = null;
 135→  }
 136→
 137→  return syncWallAttachmentPoints(nextWall, columns);
 138→}
 139→
 140→function clampWallMountedOpenings(openings, wallId, nextWallLength) {
 141→  return openings.map((opening) => {
 142→    if (opening.wallId !== wallId) return opening;
 143→
 144→    const nextOffset = clampWallOpeningOffset(nextWallLength, opening.width, opening.offset);
 145→    return nextOffset === opening.offset ? opening : { ...opening, offset: nextOffset };
 146→  });
 147→}
 148→
 149→function projectReducer(state, action) {
 150→  switch (action.type) {
 151→    case 'PROJECT_NEW': {
 152→      const newProject = syncProjectStructures({
 153→        ...action.project,
 154→        floors: sortFloors(action.project.floors || []),
 155→      });
 156→      return {
 157→        project: newProject,
 158→        isDirty: false,
 159→        lastSavedAt: null,
 160→        savedSnapshot: snapshotProject(newProject),
 161→        history: [],
 162→        future: [],
 163→      };
 164→    }
 165→
 166→    case 'PROJECT_LOAD': {
 167→      const loadedProject = syncProjectStructures({
 168→        ...action.project,
 169→        floors: sortFloors(action.project.floors || []),
 170→      });
 171→      return {
 172→        project: loadedProject,
 173→        isDirty: false,
 174→        lastSavedAt: action.savedAt || null,
 175→        savedSnapshot: snapshotProject(loadedProject),
 176→        history: [],
 177→        future: [],
 178→      };
 179→    }
 180→
 181→    case 'PROJECT_SET_NAME':
 182→      return applyProjectUpdate(state, {
 183→        ...state.project,
 184→        name: action.name,
 185→        updatedAt: new Date().toISOString(),
 186→      });
 187→
 188→    case 'PROJECT_UPDATE':
 189→      return applyProjectUpdate(state, {
 190→        ...state.project,
 191→        ...action.updates,
 192→        updatedAt: new Date().toISOString(),
 193→      });
 194→
 195→    case 'ROOF_CREATE':
 196→      return updateRoofSystem(state, () => action.roofSystem);
 197→
 198→    case 'ROOF_UPDATE':
 199→      return updateRoofSystem(state, (roofSystem) => {
 200→        if (!roofSystem || roofSystem.id !== action.roofSystem.id) return roofSystem;
 201→
 202→        const mergedRoofSystem = {
 203→          ...roofSystem,
 204→          ...action.roofSystem,
 205→        };
 206→
 207→        if ('baseElevation' in action.roofSystem) {
 208→          const attachmentBaseElevation = getAttachedTrussSystem(state.project, mergedRoofSystem)?.baseElevation
 209→            ?? getRoofAttachmentElevation(state.project);
 210→          mergedRoofSystem.attachmentOffset = (action.roofSystem.baseElevation ?? roofSystem.baseElevation)
 211→            - attachmentBaseElevation;
 212→        }
 213→
 214→        return mergedRoofSystem;
 215→      });
 216→
 217→    case 'ROOF_DELETE':
 218→      return applyProjectUpdate(state, {
 219→        ...clearStairRoofAccessReferences(state.project),
 220→        updatedAt: new Date().toISOString(),
 221→        roofSystem: null,
 222→      });
 223→
 224→    case 'TRUSS_SYSTEM_ADD':
 225→      return updateTrussSystems(state, (trussSystems) => [...trussSystems, action.trussSystem]);
 226→
 227→    case 'TRUSS_SYSTEM_UPDATE':
 228→      return updateTrussSystems(state, (trussSystems) => (
 229→        trussSystems.map((trussSystem) => {
 230→          if (trussSystem.id !== action.trussSystem.id) return trussSystem;
 231→          const nextFloorId = action.trussSystem.floorId ?? trussSystem.floorId;
 232→          return {
 233→            ...trussSystem,
 234→            ...action.trussSystem,
 235→            trussInstances: (action.trussSystem.trussInstances || trussSystem.trussInstances || []).map((trussInstance) => ({
 236→              ...trussInstance,
 237→              floorId: nextFloorId,
 238→            })),
 239→          };
 240→        })
 241→      ));
 242→
 243→    case 'TRUSS_SYSTEM_DELETE':
 244→      return updateTrussSystems(state, (trussSystems) => (
 245→        trussSystems.filter((trussSystem) => trussSystem.id !== action.trussSystemId)
 246→      ));
 247→
 248→    case 'TRUSS_INSTANCE_ADD':
 249→      return updateTrussSystems(state, (trussSystems) => (
 250→        trussSystems.map((trussSystem) => (
 251→          trussSystem.id === action.trussSystemId
 252→            ? {
 253→                ...trussSystem,
 254→                trussInstances: [...(trussSystem.trussInstances || []), action.trussInstance],
 255→              }
 256→            : trussSystem
 257→        ))
 258→      ));
 259→
 260→    case 'TRUSS_INSTANCE_UPDATE':
 261→      return updateTrussSystems(state, (trussSystems) => (
 262→        trussSystems.map((trussSystem) => (
 263→          trussSystem.id === action.trussSystemId
 264→            ? {
 265→                ...trussSystem,
 266→                trussInstances: (trussSystem.trussInstances || []).map((trussInstance) => (
 267→                  trussInstance.id === action.trussInstance.id
 268→                    ? { ...trussInstance, ...action.trussInstance, floorId: trussSystem.floorId }
 269→                    : trussInstance
 270→                )),
 271→              }
 272→            : trussSystem
 273→        ))
 274→      ));
 275→
 276→    case 'TRUSS_INSTANCE_DELETE':
 277→      return updateTrussSystems(state, (trussSystems) => (
 278→        trussSystems.map((trussSystem) => (
 279→          trussSystem.id === action.trussSystemId
 280→            ? {
 281→                ...trussSystem,
 282→                trussInstances: (trussSystem.trussInstances || []).filter((trussInstance) => trussInstance.id !== action.trussInstanceId),
 283→              }
 284→            : trussSystem
 285→        ))
 286→      ));
 287→
 288→    case 'PARAPET_ADD':
 289→      return updateRoofSystem(state, (roofSystem) => (
 290→        roofSystem
 291→          ? { ...roofSystem, parapets: [...(roofSystem.parapets || []), action.parapet] }
 292→          : roofSystem
 293→      ));
 294→
 295→    case 'PARAPET_UPDATE':
 296→      return updateRoofSystem(state, (roofSystem) => (
 297→        roofSystem
 298→          ? {
 299→              ...roofSystem,
 300→              parapets: (roofSystem.parapets || []).map((parapet) => (
 301→                parapet.id === action.parapet.id ? { ...parapet, ...action.parapet } : parapet
 302→              )),
 303→            }
 304→          : roofSystem
 305→      ));
 306→
 307→    case 'PARAPET_DELETE':
 308→      return updateRoofSystem(state, (roofSystem) => (
 309→        roofSystem
 310→          ? {
 311→              ...roofSystem,
 312→              parapets: (roofSystem.parapets || []).filter((parapet) => parapet.id !== action.parapetId),
 313→            }
 314→          : roofSystem
 315→      ));
 316→
 317→    case 'DRAIN_ADD':
 318→      return updateRoofSystem(state, (roofSystem) => (
 319→        roofSystem
 320→          ? { ...roofSystem, drains: [...(roofSystem.drains || []), action.drain] }
 321→          : roofSystem
 322→      ));
 323→
 324→    case 'DRAIN_UPDATE':
 325→      return updateRoofSystem(state, (roofSystem) => (
 326→        roofSystem
 327→          ? {
 328→              ...roofSystem,
 329→              drains: (roofSystem.drains || []).map((drain) => (
 330→                drain.id === action.drain.id ? { ...drain, ...action.drain } : drain
 331→              )),
 332→            }
 333→          : roofSystem
 334→      ));
 335→
 336→    case 'DRAIN_DELETE':
 337→      return updateRoofSystem(state, (roofSystem) => (
 338→        roofSystem
 339→          ? {
 340→              ...roofSystem,
 341→              drains: (roofSystem.drains || []).filter((drain) => drain.id !== action.drainId),
 342→            }
 343→          : roofSystem
 344→      ));
 345→
 346→    case 'ROOF_OPENING_ADD':
 347→      return updateRoofSystem(state, (roofSystem) => (
 348→        roofSystem
 349→          ? { ...roofSystem, roofOpenings: [...(roofSystem.roofOpenings || []), action.roofOpening] }
 350→          : roofSystem
 351→      ));
 352→
 353→    case 'ROOF_OPENING_UPDATE':
 354→      return updateRoofSystem(state, (roofSystem) => (
 355→        roofSystem
 356→          ? {
 357→              ...roofSystem,
 358→              roofOpenings: (roofSystem.roofOpenings || []).map((roofOpening) => (
 359→                roofOpening.id === action.roofOpening.id ? { ...roofOpening, ...action.roofOpening } : roofOpening
 360→              )),
 361→            }
 362→          : roofSystem
 363→      ));
 364→
 365→    case 'ROOF_OPENING_DELETE':
 366→      return applyProjectUpdate(state, clearStairRoofAccessReferences({
 367→        ...state.project,
 368→        updatedAt: new Date().toISOString(),
 369→        roofSystem: state.project.roofSystem
 370→          ? {
 371→              ...state.project.roofSystem,
 372→              roofOpenings: (state.project.roofSystem.roofOpenings || []).filter((roofOpening) => roofOpening.id !== action.roofOpeningId),
 373→            }
 374→          : null,
 375→      }, action.roofOpeningId));
 376→
 377→    case 'ROOF_PLANE_ADD':
 378→      return updateRoofSystem(state, (roofSystem) => (
 379→        roofSystem
 380→          ? { ...roofSystem, roofPlanes: [...(roofSystem.roofPlanes || []), action.roofPlane] }
 381→          : roofSystem
 382→      ));
 383→
 384→    case 'ROOF_PLANE_UPDATE':
 385→      return updateRoofSystem(state, (roofSystem) => (
 386→        roofSystem
 387→          ? {
 388→              ...roofSystem,
 389→              roofPlanes: (roofSystem.roofPlanes || []).map((roofPlane) => (
 390→                roofPlane.id === action.roofPlane.id ? { ...roofPlane, ...action.roofPlane } : roofPlane
 391→              )),
 392→            }
 393→          : roofSystem
 394→      ));
 395→
 396→    case 'ROOF_PLANE_DELETE':
 397→      return updateRoofSystem(state, (roofSystem) => (
 398→        roofSystem
 399→          ? {
 400→              ...roofSystem,
 401→              roofPlanes: (roofSystem.roofPlanes || []).filter((roofPlane) => roofPlane.id !== action.roofPlaneId),
 402→              roofEdges: (roofSystem.roofEdges || []).filter((roofEdge) => !((roofEdge.planeIds || []).includes(action.roofPlaneId))),
 403→            }
 404→          : roofSystem
 405→      ));
 406→
 407→    case 'ROOF_EDGE_UPDATE':
 408→      return updateRoofSystem(state, (roofSystem) => {
 409→        if (!roofSystem) return roofSystem;
 410→
 411→        const existingEdges = roofSystem.roofEdges || [];
 412→        const existingIndex = existingEdges.findIndex((roofEdge) => (
 413→          roofEdge.id === action.roofEdge.id
 414→          || (action.roofEdge.geometryKey && roofEdge.geometryKey === action.roofEdge.geometryKey)
 415→        ));
 416→
 417→        if (existingIndex === -1) {
 418→          return {
 419→            ...roofSystem,
 420→            roofEdges: [...existingEdges, action.roofEdge],
 421→          };
 422→        }
 423→
 424→        return {
 425→          ...roofSystem,
 426→          roofEdges: existingEdges.map((roofEdge, index) => (
 427→            index === existingIndex ? { ...roofEdge, ...action.roofEdge } : roofEdge
 428→          )),
 429→        };
 430→      });
 431→
 432→    case 'ROOF_EDGE_DELETE':
 433→      return updateRoofSystem(state, (roofSystem) => (
 434→        roofSystem
 435→          ? {
 436→              ...roofSystem,
 437→              roofEdges: (roofSystem.roofEdges || []).filter((roofEdge) => (
 438→                roofEdge.id !== action.roofEdgeId
 439→                && (action.geometryKey ? roofEdge.geometryKey !== action.geometryKey : true)
 440→              )),
 441→            }
 442→          : roofSystem
 443→      ));
 444→
 445→    case 'FLOOR_ADD':
 446→      return replaceFloors(state, [...state.project.floors, action.floor]);
 447→
 448→    case 'FLOOR_UPDATE':
 449→      return applyProjectUpdate(state, (() => {
 450→        let elevationDelta = 0;
 451→        const nextFloors = state.project.floors.map((floor) => {
 452→          if (floor.id !== action.floor.id) return floor;
 453→
 454→          const mergedFloor = {
 455→            ...floor,
 456→            ...action.floor,
 457→          };
 458→          const nextElevation = getFloorElevation(mergedFloor);
 459→          elevationDelta = nextElevation - getFloorElevation(floor);
 460→          return {
 461→            ...shiftFloorAbsoluteElements({
 462→              ...mergedFloor,
 463→              elevation: getFloorElevation(floor),
 464→            }, elevationDelta),
 465→            elevation: nextElevation,
 466→          };
 467→        });
 468→
 469→        const nextTrussSystems = (state.project.trussSystems || []).map((trussSystem) => (
 470→          trussSystem.floorId === action.floor.id
 471→            ? {
 472→                ...trussSystem,
 473→                baseElevation: (trussSystem.baseElevation ?? 0) + elevationDelta,
 474→              }
 475→            : trussSystem
 476→        ));
 477→
 478→        return {
 479→          ...state.project,
 480→          updatedAt: new Date().toISOString(),
 481→          floors: sortFloors(nextFloors),
 482→          trussSystems: nextTrussSystems,
 483→        };
 484→      })());
 485→
 486→    case 'FLOOR_DUPLICATE': {
 487→      const duplicatedFloor = action.floor;
 488→      const elevationShift = duplicatedFloor.floorToFloorHeight ?? 0;
 489→      const insertionLevelIndex = getFloorLevelIndex(duplicatedFloor);
 490→
 491→      const shiftedFloors = state.project.floors.map((floor) => {
 492→        if (getFloorLevelIndex(floor) < insertionLevelIndex) return floor;
 493→
 494→        const previousLevelIndex = getFloorLevelIndex(floor);
 495→        return shiftFloorElevationData({
 496→          ...floor,
 497→          name: floor.name === getDefaultFloorName(previousLevelIndex)
 498→            ? getDefaultFloorName(previousLevelIndex + 1)
 499→            : floor.name,
 500→          levelIndex: previousLevelIndex + 1,
 501→        }, elevationShift);
 502→      });
 503→
 504→      return replaceFloors(state, [...shiftedFloors, duplicatedFloor]);
 505→    }
 506→
 507→    case 'FLOOR_DELETE': {
 508→      if (state.project.floors.length <= 1) return state;
 509→
 510→      const nextProject = replaceDeletedFloorReferences(
 511→        {
 512→          ...state.project,
 513→          floors: state.project.floors.filter((floor) => floor.id !== action.floorId),
 514→          trussSystems: (state.project.trussSystems || []).filter((trussSystem) => trussSystem.floorId !== action.floorId),
 515→        },
 516→        action.floorId,
 517→        action.fallbackFloorId
 518→      );
 519→
 520→      return applyProjectUpdate(state, {
 521→        ...nextProject,
 522→        updatedAt: new Date().toISOString(),
 523→        floors: sortFloors(nextProject.floors),
 524→      });
 525→    }
 526→
 527→    case 'SHEET_ADD':
 528→      return applyProjectUpdate(state, {
 529→        ...state.project,
 530→        updatedAt: new Date().toISOString(),
 531→        sheets: [...(state.project.sheets || []), action.sheet],
 532→      });
 533→
 534→    case 'SHEET_UPDATE':
 535→      return applyProjectUpdate(state, {
 536→        ...state.project,
 537→        updatedAt: new Date().toISOString(),
 538→        sheets: (state.project.sheets || []).map((sheet) => (
 539→          sheet.id === action.sheet.id ? { ...sheet, ...action.sheet } : sheet
 540→        )),
 541→      });
 542→
 543→    case 'SHEET_DELETE':
 544→      return applyProjectUpdate(state, {
 545→        ...state.project,
 546→        updatedAt: new Date().toISOString(),
 547→        sheets: (state.project.sheets || []).filter((sheet) => sheet.id !== action.sheetId),
 548→      });
 549→
 550→    case 'SHEET_VIEWPORT_ADD':
 551→      return applyProjectUpdate(state, {
 552→        ...state.project,
 553→        updatedAt: new Date().toISOString(),
 554→        sheets: (state.project.sheets || []).map((sheet) => (
 555→          sheet.id === action.sheetId
 556→            ? { ...sheet, viewports: [...(sheet.viewports || []), action.viewport] }
 557→            : sheet
 558→        )),
 559→      });
 560→
 561→    case 'SHEET_VIEWPORT_UPDATE':
 562→      return applyProjectUpdate(state, {
 563→        ...state.project,
 564→        updatedAt: new Date().toISOString(),
 565→        sheets: (state.project.sheets || []).map((sheet) => (
 566→          sheet.id === action.sheetId
 567→            ? {
 568→                ...sheet,
 569→                viewports: (sheet.viewports || []).map((viewport) => (
 570→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
 571→                )),
 572→              }
 573→            : sheet
 574→        )),
 575→      });
 576→
 577→    case 'SHEET_VIEWPORT_DELETE':
 578→      return applyProjectUpdate(state, {
 579→        ...state.project,
 580→        updatedAt: new Date().toISOString(),
 581→        sheets: (state.project.sheets || []).map((sheet) => (
 582→          sheet.id === action.sheetId
 583→            ? {
 584→                ...sheet,
 585→                viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId),
 586→              }
 587→            : sheet
 588→        )),
 589→      });
 590→
 591→    case 'WALL_ADD':
 592→      return updateFloor(state, action.floorId, f => ({
 593→        ...f,
 594→        walls: [...f.walls, syncWallAttachmentPoints(action.wall, f.columns || [])],
 595→      }));
 596→
 597→    case 'WALL_UPDATE':
 598→      return updateFloor(state, action.floorId, f => {
 599→        let updatedWall = null;
 600→        const walls = f.walls.map((wall) => {
 601→          if (wall.id !== action.wall.id) return wall;
 602→
 603→          updatedWall = mergeWallUpdate(wall, action.wall, f.columns || []);
 604→          return updatedWall;
 605→        });
 606→
 607→        if (!updatedWall) {
 608→          return f;
 609→        }
 610→
 611→        const nextWallLength = wallLength(updatedWall);
 612→
 613→        return {
 614→          ...f,
 615→          walls,
 616→          doors: clampWallMountedOpenings(f.doors, updatedWall.id, nextWallLength),
 617→          windows: clampWallMountedOpenings(f.windows, updatedWall.id, nextWallLength),
 618→        };
 619→      });
 620→
 621→    case 'WALL_DELETE': {
 622→      const wallId = action.wallId;
 623→      return updateFloor(state, action.floorId, f => ({
 624→        ...f,
 625→        walls: f.walls.filter(w => w.id !== wallId),
 626→        doors: f.doors.filter(d => d.wallId !== wallId),
