409→      } else if (selectedType === 'landing') {
410→        const landing = (floor.landings || []).find(l => l.id === selectedId);
411→        if (!landing) return;
412→        dispatch({
413→          type: 'LANDING_UPDATE',
414→          floorId: activeFloorId,
415→          landing: {
416→            id: landing.id,
417→            position: {
418→              x: landing.position.x + dx,
419→              y: landing.position.y + dy,
420→            },
421→          },
422→        });
423→        editorDispatch({
424→          type: 'UPDATE_TOOL_STATE',
425→          payload: { startPos: modelPos },
426→        });
427→      } else if (selectedType === 'slab') {
428→        if (toolState.dragType !== 'handle' || toolState.handle !== 'slab-vertex' || toolState.handleIndex == null) {
429→          return;
430→        }
431→        const slab = (floor.slabs || []).find(s => s.id === selectedId);
432→        if (!slab) return;
433→
434→        const boundaryPoints = slab.boundaryPoints.map((point, index) => (
435→          index === toolState.handleIndex ? { x: modelPos.x, y: modelPos.y } : point
436→        ));
437→
438→        dispatch({
439→          type: 'SLAB_UPDATE',
440→          floorId: activeFloorId,
441→          slab: {
442→            id: slab.id,
443→            boundaryPoints,
444→          },
445→        });
446→        editorDispatch({
447→          type: 'UPDATE_TOOL_STATE',
448→          payload: { startPos: modelPos },
449→        });
450→      } else if (selectedType === 'door' || selectedType === 'window') {
451→        // Slide along parent wall
452→        const items = selectedType === 'door' ? floor.doors : floor.windows;
453→        const item = items.find(i => i.id === selectedId);
454→        if (!item) return;
455→
456→        const wall = floor.walls.find(w => w.id === item.wallId);
457→        if (!wall) return;
458→
459→        const newOffset = projectPointOnWall(wall, modelPos);
460→        const clampedOffset = clampWallOpeningOffset(wallLength(wall), item.width, newOffset);
461→
462→        const updateType = selectedType === 'door' ? 'DOOR_UPDATE' : 'WINDOW_UPDATE';
463→        dispatch({
464→          type: updateType,
465→          floorId: activeFloorId,
466→          [selectedType]: { id: item.id, offset: clampedOffset },
467→        });
468→
469→        editorDispatch({
470→          type: 'UPDATE_TOOL_STATE',
471→          payload: { startPos: modelPos },
472→        });
473→      }
474→    },
475→
476→    onMouseUp(modelPos, e, toolState) {
477→      if (toolState.dragging && toolState.dragType === 'marquee') {
478→        const floor = getFloor(activeFloorId);
479→        const bounds = normalizeRectBounds(toolState.startPos || modelPos, toolState.currentPos || modelPos);
480→        const size = rectSize(bounds);
481→        const minimumSize = SNAP_DISTANCE_PX / viewport.zoom;
482→
483→        if (!floor || (size.width < minimumSize && size.height < minimumSize)) {
484→          editorDispatch({ type: 'DESELECT' });
485→        } else {
486→          const regionSelection = collectPlanRegionSelection(floor, bounds);
487→          if (regionSelection.objectCount) {
488→            editorDispatch({
489→              type: 'SET_REGION_SELECTION',
490→              bounds: regionSelection.bounds,
491→              selection: regionSelection.selection,
492→            });
493→          } else {
494→            editorDispatch({ type: 'DESELECT' });
495→          }
496→        }
497→
498→        editorDispatch({
499→          type: 'UPDATE_TOOL_STATE',
500→          payload: {
501→            dragging: false,
502→            dragType: null,
503→            handle: null,
504→            handleIndex: null,
505→            startPos: null,
506→            currentPos: null,
507→          },
508→        });
509→        return;
510→      }
511→
512→      if (toolState.dragging) {
513→        editorDispatch({
514→          type: 'UPDATE_TOOL_STATE',
515→          payload: {
516→            dragging: false,
517→            dragType: null,
518→            handle: null,
519→            handleIndex: null,
520→            startPos: null,
521→            originalPos: null,
522→            currentPos: null,
523→          },
524→        });
525→      }
526→    },
527→
528→    onKeyDown(e, toolState, selectedId, selectedType) {
529→      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'd' && selectedId && selectedType === 'column') {
530→        e.preventDefault();
531→        const floor = getFloor(activeFloorId);
532→        if (!floor) return;
533→        const column = (floor.columns || []).find(c => c.id === selectedId);
534→        if (!column) return;
535→        const duplicate = duplicateColumn(column);
536→        dispatch({ type: 'COLUMN_DUPLICATE', floorId: activeFloorId, column: duplicate });
537→        editorDispatch({ type: 'SELECT_OBJECT', id: duplicate.id, objectType: 'column' });
538→        return;
539→      }
540→
541→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
542→        const floor = getFloor(activeFloorId);
543→        if (!floor) return;
544→        if (selectedType === 'wall') {
545→          dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
546→        } else if (selectedType === 'door') {
547→          dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
548→        } else if (selectedType === 'window') {
549→          dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
550→        } else if (selectedType === 'column') {
551→          dispatch({ type: 'COLUMN_DELETE', floorId: activeFloorId, columnId: selectedId });
552→        } else if (selectedType === 'fixture') {
553→          dispatch({ type: 'FIXTURE_DELETE', floorId: activeFloorId, fixtureId: selectedId });
554→        } else if (selectedType === 'beam') {
555→          dispatch({ type: 'BEAM_DELETE', floorId: activeFloorId, beamId: selectedId });
556→        } else if (selectedType === 'stair') {
557→          dispatch({ type: 'STAIR_DELETE', floorId: activeFloorId, stairId: selectedId });
558→        } else if (selectedType === 'landing') {
559→          dispatch({ type: 'LANDING_DELETE', floorId: activeFloorId, landingId: selectedId });
560→        } else if (selectedType === 'annotation') {
561→          dispatch({ type: 'ANNOTATION_DELETE', floorId: activeFloorId, annotationId: selectedId });
562→        } else if (selectedType === 'slab') {
563→          dispatch({ type: 'SLAB_DELETE', floorId: activeFloorId, slabId: selectedId });
564→        } else if (selectedType === 'railing') {
565→          dispatch({ type: 'RAILING_DELETE', floorId: activeFloorId, railingId: selectedId });
566→        } else if (selectedType === 'sectionCut') {
567→          dispatch({ type: 'SECTION_DELETE', floorId: activeFloorId, sectionId: selectedId });
568→        } else if (selectedType === 'room') {
569→          dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
570→        }
571→        editorDispatch({ type: 'DESELECT' });
572→      }
573→    },
574→
575→    getCursor(toolState) {
576→      if (toolState.dragType === 'marquee') return 'crosshair';
577→      if (toolState.dragging) return 'grabbing';
578→      return 'default';
579→    },
580→  };
581→}
