124→  }
125→
126→  const axisAlignment = Math.abs(cross(startBeam.axis, endBeam.axis));
127→  if (axisAlignment > PARALLEL_TOLERANCE) {
128→    return { valid: false, message: 'Support beams must be parallel.' };
129→  }
130→
131→  if (Math.abs(startBeam.topElevation - endBeam.topElevation) > ELEVATION_TOLERANCE) {
