169→    baseElevation: startBeam.topElevation,
170→    axis: oriented.axis,
171→    spanDirection: oriented.spanDirection,
172→    supportLines: {
173→      start: {
174→        startPoint: startSupportA,
175→        endPoint: endSupportA,
176→      },
177→      end: {
178→        startPoint: startSupportB,
179→        endPoint: endSupportB,
